      "2_2_mly_small_spiral": "2.2 Mly — spiral yar",
      "local_group_80_galaxies_in_10_million_": "Kooxda Deegaanka — ~80 galaxy oo ku jira 10 milyan sano-iftiin",
      "our_local_group_has_80_galaxies_domina": "Kooxdeenna Deegaanku waxay leedahay ~80 galaxy oo ay Milky Way + Andromeda ku badan yihiin. Andromeda wuxuu ku soo dhowaanayaa 110 km/s — isku dhac ayaa suurtogal ah qiyaastii 4-5 bilyan sano gudahood. Haddii ay dhacdo: galaxy-ga weyn ee Milkomeda.",
      "asteroid_impact_outcomes": "☄ Natiijooyinka Isku Dhaca Asteroid-ka",
      "what_size_asteroid_kills_which_level_o": "Asteroid cabbirkee ayaa dila heerkee nolol ah? Barbardhig dhagax yar ilaa kan dinosaur-ka dilay.",
      "size_m": "Cabbir (m)",
      "atmospheric_entry_destroys_most_rocks_": "Galitaanka hawadu wuxuu burburiyaa dhagxaanta intooda badan ee < 5m. Chelyabinsk 2013 (20m) wuxuu jebiyay daaqadaha laakiin god ma samayn. Tunguska 1908 (50m) wuxuu simay 2000km² oo kayn ah. Chicxulub 66Ma (10km) wuxuu dilay dinosaur-yada.",
      "coronal_mass_ejection": "⚡ Coronal Mass Ejection",
      "a_cme_blasts_billions_of_tons_of_plasm": "CME wuxuu Qorraxda ka tuuraa bilyanaan tan oo plasma ah. Maalmo kadib, wuxuu keeni karaa aurora quruxsan + fashilka GPS.",
      "earth_14": "Dhul",
      "aurora": "⚡ AURORA!",
      "time_after_launch": "Wakhtiga duulista kadib",
      "cme_size": "Cabbirka CME",
      "a_coronal_mass_ejection_blasts_billion": "Coronal Mass Ejection wuxuu bilyanaan tan oo plasma ah bannaanka ku tuuraa 1-2 milyan mph. Wuxuu qaataa 1-5 maalmood inuu Dhulka gaadho. CME-yada xoogga leh waxay keenaan duufaanno geomagnetic ah, aurora dhalaalaya, waxayna carqaladayn karaan dayax-gacmeedyada + shabakadaha korontada.",
      "cepheid_variable_star": "💫 Xiddiga Cepheid Variable",
      "cepheids_pulse_on_a_regular_cycle_thei": "Cepheid-yadu waxay garaacaan wareeg joogto ah. Muddadoodu waxay muujisaa dhalaalkooda dhabta ah — cabbiraadda koonka.",
      "cepheid_variable_star_2": "Xiddiga Cepheid Variable",
      "time_days": "Wakhti (maalmo)",
      "period_2": "Muddo",
      "cepheid_variables_pulse_on_a_regular_c": "Cepheid variable-yadu waxay garaacaan wareeg joogto ah. Muddadoodu si toos ah ayay ula xiriirtaa dhalaalkooda dhabta ah (Henrietta Leavitt 1908). Cirbixiyeennadu waxay cabbiraan muddada + waxay ku isticmaalaan si ay u ogaadaan dhalaalka dhabta ah + masaafada.",
      "comet_orbit_drawer": "☄ Sawiraha Wareegga Comet-ka",
      "orbits_range_from_circles_to_long_elli": "Wareegyadu waxay u dhexeeyaan goobaabin ilaa ellipse dheer. Beddel eccentricity si aad u sawirto jidad planet u eg ama comet u eg.",
      "perihelion_2": "Perihelion",
      "aphelion_2": "Aphelion",
      "eccentricity_2": "Eccentricity",
      "orbital_eccentricity_goes_from_0_perfe": "Eccentricity-ga wareeggu wuxuu ka bilaabmaa 0 (goobaabin sax ah) ilaa 1 (bixitaan parabolic ah). Planet-yadu ku dhowaad waa goobaabin. Comet-yadu aad bay ukun ugu eg yihiin — waxay Qorraxda u soo dhowaadaan + way u fogaadaan nidaamka dibedda. Wareegyada hyperbolic (e>1) waxay ka dhigan yihiin marid hal mar ah oo nidaamka qorraxda ah.",
      "atmospheric_window": "🌐 Daaqadda Hawada",
      "earth_s_atmosphere_blocks_most_wavelen": "Hawada Dhulku waxay xannibtaa wavelength badan. Iftiinka la arki karo, raadiyaha, iyo daaqado infrared ah qaar ayaa dhulka gaadha.",
      "earth_ground_level": "Heerka dhulka ee Dhulka",
      "visible_light_radio_waves_penetrate_th": "✔ Iftiinka la arki karo, mawjadaha raadiyaha, iyo infrared qaar ayaa dhulka gaadha",
      "earth_atmosphere_blocks_most_wavelengt": "Hawada Dhulku waxay xannibtaa wavelength badan. Iftiinka la arki karo, raadiyaha, iyo daaqado infrared ah qaar ayaa dhulka gaadha; UV, X-ray, gamma-ray, iyo infrared badan waxay u baahan yihiin goobo indho-indhayn oo bannaanka ku sugan sida Hubble, JWST, Chandra, iyo Fermi.",
      "star_spectra_comparison": "📊 Isbarbardhigga Spectra-da Xiddigaha",
      "spectra_reveal_temperature_composition_motion": "Spectra-du waxay muujiyaan heerkulka, waxa uu ka kooban yahay, dhaqdhaqaaqa, iyo tilmaamo ku saabsan marxaladda horumarka walaxda.",
      "sun_g2_star": "Qorrax (xiddig G2 V)",
